/**
 * Sanitiza a saГ­da do modelo para garantir que sГі passe JSON limpo.
 * Remove markdown, cercas de cГіdigo, explicaГ§Гµes extras, # headers etc.
 */

function sanitizeRaw(raw) {
  if (!raw) return "";

  // Remove cercas de cГіdigo e markdown
  let clean = String(raw)
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();

  // Remove tГ­tulos e hashes de markdown (#, ##, ###)
  clean = clean.replace(/^\s*#+\s*/gm, "");

  // Remove separadores tipo '---'
  clean = clean.replace(/^[-]{3,}$/gm, "");

  // Pega sГі o primeiro objeto JSON vГЎlido (se houver)
  const start = clean.indexOf("{");
  const end = clean.lastIndexOf("}");
  if (start !== -1 && end !== -1) {
    clean = clean.slice(start, end + 1);
  }

  return clean;
}

const raw = $json.text || $json.data || $json.output || JSON.stringify($json);
const clean = sanitizeRaw(raw);

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  // fallback: envia como texto cru dentro do array, evita quebrar o fluxo
  parsed = { messages: [clean] };
}

return parsed;

// Garante que o valor "mensagem" exista
const texto = $json.output || $json.mensagem || "";
const mensagem = texto.trim();

// Lista de comandos vГЎlidos (case-insensitive)
const comandos = [
  "CORTAR VГЌDEO",
  "CORTA VГЌDEO",
  "EDITAR",
  "DOWNLOAD",
  "VIRAL CTA",
  "PUBLICAR",
  "REDIMENSIONAR",
  "VERTICAL",
  "CLIPS",
  "LEGENDAR"
];

// Extrai a primeira linha nГЈo vazia
const primeiraLinha = mensagem
  .split("\n")
  .map(l => l.trim())
  .filter(l => l !== "")[0] || "";

// Converte para maiГєsculas pra comparar
const primeiraUpper = primeiraLinha.toUpperCase();

// Verifica se Г© um comando vГЎlido
const ehComando = comandos.some(cmd => primeiraUpper.startsWith(cmd));

// Retorna resultado padronizado (sempre um array de objetos)
return [
  {
    tipo: ehComando ? "comando" : "texto",
    mensagem: mensagem
  }
];
